#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

// Struct to hold tiling data passed via GM_ADDR tiling
struct ConvDepthwise2dAsymmetricInputSquareKernelCustomTilingData {
    uint32_t N;
    uint32_t C;
    uint32_t H;
    uint32_t W;
    uint32_t KH;
    uint32_t KW;
    uint32_t strideH;
    uint32_t strideW;
    uint32_t padH;
    uint32_t padW;
    uint32_t dilationH;
    uint32_t dilationW;
    uint32_t groups;
    uint32_t outputH;
    uint32_t outputW;
    uint32_t tileSize;
    uint32_t blockDim;
};

class KernelConvDepthwise2dAsymmetricInputSquareKernelCustom {
public:
    __aicore__ inline KernelConvDepthwise2dAsymmetricInputSquareKernelCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR weight, GM_ADDR y,
                                const ConvDepthwise2dAsymmetricInputSquareKernelCustomTilingData &td)
    {
        N_ = td.N;
        C_ = td.C;
        H_ = td.H;
        W_ = td.W;
        KH_ = td.KH;
        KW_ = td.KW;
        strideH_ = td.strideH;
        strideW_ = td.strideW;
        padH_ = td.padH;
        padW_ = td.padW;
        dilationH_ = td.dilationH;
        dilationW_ = td.dilationW;
        groups_ = td.groups;
        outputH_ = td.outputH;
        outputW_ = td.outputW;
        tileSize_ = td.tileSize;

        xGm_.SetGlobalBuffer((__gm__ float*)x, N_ * C_ * H_ * W_);
        wGm_.SetGlobalBuffer((__gm__ float*)weight, groups_ * (C_ / groups_) * KH_ * KW_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, N_ * C_ * outputH_ * outputW_);
    }

    __aicore__ inline void Process()
    {
        if (tileSize_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        uint32_t totalOut = N_ * C_ * outputH_ * outputW_;
        uint32_t strideElems = blockNum * tileSize_;
        uint32_t base = blockIdx * tileSize_;
        while (base < totalOut) {
            uint32_t curLen = (base + tileSize_ <= totalOut) ? tileSize_ : (totalOut - base);
            // Process each output element individually
            for (uint32_t i = 0; i < curLen; i++) {
                uint32_t idx = base + i;
                uint32_t n, c, oh, ow;
                LinearToIndex(idx, n, c, oh, ow);

                // Depthwise: group = c (since groups == C)
                uint32_t group = c;
                uint32_t wOffset = group * KH_ * KW_;

                // Convolution
                int32_t hStart = oh * strideH_ - padH_;
                int32_t wStart = ow * strideW_ - padW_;
                float result = 0.0f;
                for (uint32_t kh = 0; kh < KH_; kh++) {
                    for (uint32_t kw = 0; kw < KW_; kw++) {
                        int32_t ih = hStart + kh * dilationH_;
                        int32_t iw = wStart + kw * dilationW_;
                        if (ih >= 0 && ih < (int32_t)H_ && iw >= 0 && iw < (int32_t)W_) {
                            uint32_t xIdx = n * C_ * H_ * W_ + c * H_ * W_ + ih * W_ + iw;
                            float xVal = xGm_.GetValue(xIdx);
                            uint32_t wIdx = wOffset + kh * KW_ + kw;
                            float wVal = wGm_.GetValue(wIdx);
                            result += xVal * wVal;
                        }
                    }
                }
                yGm_.SetValue(idx, result);
            }
            base += strideElems;
        }
    }

private:
    __aicore__ inline void LinearToIndex(uint32_t idx, uint32_t &n, uint32_t &c,
                                          uint32_t &oh, uint32_t &ow) const
    {
        uint32_t spatialSize = outputH_ * outputW_;
        n = idx / (C_ * spatialSize);
        uint32_t rem = idx % (C_ * spatialSize);
        c = rem / spatialSize;
        uint32_t spatialIdx = rem % spatialSize;
        oh = spatialIdx / outputW_;
        ow = spatialIdx % outputW_;
    }

private:
    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> wGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t N_, C_, H_, W_;
    uint32_t KH_, KW_;
    uint32_t strideH_, strideW_;
    uint32_t padH_, padW_;
    uint32_t dilationH_, dilationW_;
    uint32_t groups_;
    uint32_t outputH_, outputW_;
    uint32_t tileSize_;
};

extern "C" __global__ __aicore__ void conv_depthwise_2d_asymmetric_input_square_kernel_custom(
    GM_ADDR x, GM_ADDR weight, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelConvDepthwise2dAsymmetricInputSquareKernelCustom op;
    // Copy tiling data into local struct (fields will be in the same order)
    ConvDepthwise2dAsymmetricInputSquareKernelCustomTilingData td;
    td.N = tiling_data.N;
    td.C = tiling_data.C;
    td.H = tiling_data.H;
    td.W = tiling_data.W;
    td.KH = tiling_data.KH;
    td.KW = tiling_data.KW;
    td.strideH = tiling_data.strideH;
    td.strideW = tiling_data.strideW;
    td.padH = tiling_data.padH;
    td.padW = tiling_data.padW;
    td.dilationH = tiling_data.dilationH;
    td.dilationW = tiling_data.dilationW;
    td.groups = tiling_data.groups;
    td.outputH = tiling_data.outputH;
    td.outputW = tiling_data.outputW;
    td.tileSize = tiling_data.tileSize;
    td.blockDim = tiling_data.blockDim;
    op.Init(x, weight, y, td);
    op.Process();
}
